GamePlayer = class("GamePlayer", BasePlayer)

function GamePlayer:init()
    self:initStaticAttr()
    self:initAttr()
    self:teleportPosWithYaw(GameConfig.initPos, GameConfig.initPosYaw)
end

function GamePlayer:initAttr()
    self.lastMoveTime = os.time()
    self.lastMoveHash = ""
    self.Wallet = GameWallet.new(self:getEntityPlayer():getWallet(), self.rakssid)
    self.Wallet:setMoneyCount(Define.Money.HallGold, 0)
    self:addItem(2801, 1)

    --Db Data
    self.level = 1
    self.cur_exp = 0
    self.equipSkinId = 0

    self.checkPointRecord = {}
    self.hallInfo = {}
    self.gameReward = {}
    self.towerList = {}     --塔
    self.skinList = {}      --皮肤
    self.payItemList = {}   --特权

    self.addSpeed = 0

    HostApi.changePlayerPerspece(self.rakssid, 1)
end

function GamePlayer:checkHangUp()
    if os.time() - self.lastMoveTime >= GameConfig.HangUpTime then
        BaseListener.onPlayerLogout(self.userId)
        HostApi.sendGameover(self.rakssid, IMessages:msgGameOver(), GameOverCode.GameOver)
    end
end

function GamePlayer:addFreeTowerToList()
    local freeTowers = TowerConfig:getFreeTowerList()
    for _, tower in pairs(freeTowers) do
        if self.towerList[tower.Id] == nil then
            self:addNewTower(tower.Id)
        end
    end
end

function GamePlayer:consumeReward()
    for _, groupId in pairs(self.gameReward) do
        local rewards = RewardConfig:getRewardGround(tonumber(groupId))
        for _, reward in pairs(rewards) do
            if GameReward:onPlayerGetReward(self, reward) then
                --print("success")
            end
        end
    end
    self.gameReward = {}
end

function GamePlayer:addExp(exp)
    GamePacketSender:sendAddExp(self, exp)
    local beforeLv = self.level
    local cur_max, is_max = ExpConfig:getMaxExp(self.level)
    if not is_max then
        self.cur_exp = self.cur_exp + exp
    end
    local rewards = {}
    while not is_max and self.cur_exp >= cur_max do
        self.cur_exp = self.cur_exp - cur_max
        rewards = self:levelUp(self.level + 1, rewards)
        cur_max, is_max = ExpConfig:getMaxExp(self.level)
    end
    if is_max then
        self.cur_exp = 0
    end
    --显示升级界面
    if self.level > beforeLv then
        GamePacketSender:sendUpgradeInfo(self, rewards, beforeLv, self.level)
    end
end

function GamePlayer:levelUp(level, rewards)
    self.level = level
    local rewardIds = ExpConfig:getLevelReward(self.level)
    for _, id in pairs(rewardIds) do
        local reward = RewardConfig:getRewardById(tonumber(id))
        GameReward:onPlayerGetReward(self, reward)
        if not rewards[tostring(reward.RewardType)] then
            rewards[tostring(reward.RewardType)] = 0
        end
        rewards[tostring(reward.RewardType)] = rewards[tostring(reward.RewardType)] + reward.Count
    end
    self:updateShowName()

    if self.hasReport == true then
        GameAnalytics:design(self.userId, 1, { "Player_Lv", self.level })
        GameAnalytics:design(self.userId, -1, { "Player_Lv", self.level - 1 })
    end

    return rewards
end

function GamePlayer:addNewTower(towerId)
    local tower = {
        towerId = towerId,
        isHave = true,
        isHaveBook = false,
        openBookTimes = 0,
        isNew = true,
        buildTimes = 0,
    }
    self.towerList[towerId] = tower
    return true
end

function GamePlayer:addNewTowerBook(towerId)
    if self.towerList[towerId] == nil then
        return false
    end
    self.towerList[towerId].isHaveBook = true
end

function GamePlayer:onOpenBookDetail(towerId)
    if self.towerList[towerId] and self.towerList[towerId].isHaveBook then
        self.towerList[towerId].isNew = false
        self.towerList[towerId].openBookTimes = self.towerList[towerId].openBookTimes + 1
    end
    ReportUtil.reportClickHallBookItem(self, towerId)
end

function GamePlayer:buildShowName()
    local nameList = {}
    local namePrefix = TextFormat.colorGreen .. "[Lv." .. tostring(self.level) .. "] "
    local disName = self.name
    PlayerIdentityCache:buildNameList(self.userId, nameList, disName, namePrefix)
    return table.concat(nameList, "\n")
end

function GamePlayer:updateShowName()
    self:setShowName(self:buildShowName())
    self.clientPeer:setShowName(" ", self.rakssid)
end

function GamePlayer:initSkin()
    if self.equipSkinId ~= 0 then
        self:equipSkin(self.equipSkinId)
        GamePacketSender:sendSkinInfo(self)
        return
    end
    local sex = self:getSex()
    if sex == Define.Sex.Boy then
        self:onGetNewSkin(GameConfig.defaultBoySkin)
    else
        self:onGetNewSkin(GameConfig.defaultGirlSkin)
    end
end

function GamePlayer:equipSkin(skinId)
    local config = SkinStoreConfig:getConfigById(skinId)
    if config and self.skinList[tostring(skinId)] and self.skinList[tostring(skinId)].isHave == true then
        self:changeActor(config.actorName)
        self.equipSkinId = skinId
        GamePacketSender:sendEquipSkin(self)
    end
end

function GamePlayer:onGetNewSkin(skinId)
    local config = SkinStoreConfig:getConfigById(skinId)
    if config then
        local skin = {
            id = skinId,
            isHave = true,
        }
        self.skinList = self.skinList or {}
        self.skinList[tostring(skinId)] = skin
    end
    self:equipSkin(skinId)
    GamePacketSender:sendSkinInfo(self)
end

function GamePlayer:changeSpeed(speed)
    self.addSpeed = self.addSpeed + speed
    self.entityPlayerMP:setSpeedAdditionLevel(self.addSpeed)
end